// Шинэ ажилтны ID-г салбараар автомат үүсгэх + давхцал шалгах
const body = $('Webhook · Бүртгэл хүсэлт').first().json.body || {};
const existing = $input.all().map(it => it.json);

const name  = String(body.name || '').trim();
const role  = String(body.role || '').trim();
const group = String(body.group || '').trim();
const phone = String(body.phone || '').trim();
const email = String(body.email || '').trim();
const pin   = String(body.pin || '').trim();

if (!name)  throw new Error('Овог нэр шаардлагатай');
if (!role)  throw new Error('Албан тушаал шаардлагатай');
if (!group) throw new Error('Бүлэг шаардлагатай');
if (!phone || phone.replace(/\\D/g,'').length < 8) throw new Error('Утасны дугаар шаардлагатай');
if (!email) throw new Error('И-мэйл шаардлагатай');
if (!/^[0-9]{4}$/.test(pin)) throw new Error('PIN нь 4 оронтой тоо байх ёстой');

// PIN давхцал (монгол 'PIN' баганаас)
const pinExists = existing.some(r => String(r['PIN'] || '').trim() === pin);
if (pinExists) throw new Error('Энэ PIN өөр хүн ашиглаж байна');

// Утас давхцал
const phoneNorm = phone.replace(/[^0-9]/g, '');
if (phoneNorm && existing.some(r => String(r['Утас'] || '').replace(/[^0-9]/g, '') === phoneNorm)) {
  throw new Error('Энэ утасны дугаараар бүртгэлтэй байна');
}
// И-мэйл давхцал
if (email && existing.some(r => String(r['И-мэйл'] || '').trim().toLowerCase() === email.toLowerCase())) {
  throw new Error('Энэ и-мэйл хаягаар бүртгэлтэй байна');
}

// ID prefix салбараар
const PREFIX_MAP = { 'Нэгдсэн': 'S', 'M Event': 'M', 'Camp': 'C' };
const prefix = PREFIX_MAP[group] || 'X';

// Дараагийн чөлөөт дугаар ('ID' монгол баганаас)
const usedIds = new Set(existing.map(r => String(r['ID'] || '').trim()));
let i = 1;
let newId = prefix + String(i).padStart(2, '0');
while (usedIds.has(newId)) { i++; newId = prefix + String(i).padStart(2, '0'); }

const today = new Date().toISOString().slice(0, 10);

// ГАРАЛТ: Sheet-н толгойтой ЯГ ИЖИЛ монгол түлхүүр (auto-map таарна)
return [{ json: {
  'ID': newId,
  'Овог нэр': name,
  'Албан тушаал': role,
  'Бүлэг': group,
  'Зэрэглэл': 40,
  'Утас': phone,
  'И-мэйл': email,
  'PIN': pin,
  'Төлөв': 'идэвхтэй',
  'Ажилд орсон': today,
  'Тэмдэглэл': 'Апп-аар өөрөө бүртгүүлсэн',
} }];
